// ─── Types ────────────────────────────────────────────────────────────────────

type TText    = { id: string; type: "text";    icon: string; q: string; sub: string; placeholder: string; label: string };
type TOptions = { id: string; type: "options"; icon: string; q: string; sub: string; options: { i: string; t: string }[] };
type TMulti   = { id: string; type: "multi";   icon: string; q: string; sub: string; options: { i: string; t: string }[] };
type TScale   = { id: string; type: "scale";   icon: string; q: string; sub: string; min: number; max: number };
type Question = TText | TOptions | TMulti | TScale;
interface StepDef { label: string; questions: Question[] }

